fn is_private_ip(ip: IpAddr) -> bool {
    match ip {
        IpAddr::V4(ipv4) => {
            ipv4.is_private()
                || ipv4.is_loopback()
                || ipv4.is_link_local()
                || ipv4.is_broadcast()
                || ipv4.is_documentation()
                || ipv4.is_unspecified()
                || ipv4.octets()[0] == 169 && ipv4.octets()[1] == 254
                || ipv4.octets()[0] == 100
                    && ipv4.octets()[1] >= 64
                    && ipv4.octets()[1] <= 127
        }
        IpAddr::V6(ipv6) => {
            ipv6.is_loopback()
                || ipv6.is_unspecified()
                || ((ipv6.segments()[0] & 0xfe00) == 0xfc00)
                || ((ipv6.segments()[0] & 0xffc0) == 0xfe80)
                || ipv6.segments()[0] == 0x2001 && ipv6.segments()[1] == 0xdb8
        }
    }
}

fn is_allowed_url(url: &Url) -> Result<(), String> {
    let scheme = url.scheme();
    if scheme != "http" && scheme != "https" {
        return Err("Only HTTP and HTTPS schemes are allowed".to_string());
    }

    let host = url.host_str().ok_or("Invalid host")?;

    if host == "localhost"
        || host.ends_with(".local")
        || host.ends_with(".localhost")
        || host == "0.0.0.0"
        || host == "[::]"
    {
        return Err("Localhost and local domains are not allowed".to_string());
    }

    if let Ok(ip) = host.parse::<IpAddr>() {
        if is_private_ip(ip) {
            return Err("Private IP addresses are not allowed".to_string());
        }
    }

    if let Some(domain) = url.domain() {
        if domain.starts_with("169.254.")
            || domain.starts_with("127.")
            || domain == "metadata.google.internal"
            || domain.ends_with(".amazonaws.com")
            || domain.ends_with(".metadata.azure.com")
        {
            return Err("Blocked domain".to_string());
        }
    }

    Ok(())
}

async fn proxy_handler(Query(params): Query<ProxyParams>) -> Response {
    let url = match Url::parse(&params.url) {
        Ok(u) => u,
        Err(_) => {
            return (StatusCode::BAD_REQUEST, "Invalid URL").into_response();
        }
    };

    if let Err(e) = is_allowed_url(&url) {
        return (StatusCode::FORBIDDEN, e).into_response();
    }

    let client = match Client::builder()
        .timeout(Duration::from_secs(10))
        .redirect(reqwest::redirect::Policy::limited(3))
        .build()
    {
        Ok(c) => c,
        Err(_) => {
            return (StatusCode::INTERNAL_SERVER_ERROR, "Failed to create client")
                .into_response();
        }
    };

    match client.get(url.as_str()).send().await {
        Ok(response) => {
            let status = response.status();
            let headers = response.headers().clone();
            
            match response.bytes().await {
                Ok(body) => {
                    let mut resp = (status, body).into_response();
                    
                    for (key, value) in headers.iter() {
                        if key != "content-length" 
                            && key != "transfer-encoding" 
                            && key != "connection" {
                            if let Ok(header_name) = axum::http::HeaderName::from_bytes(key.as_str().as_bytes()) {
                                if let Ok(header_value) = axum::http::HeaderValue::from_bytes(value.as_bytes()) {
                                    resp.headers_mut().insert(header_name, header_value);
                                }
                            }
                        }
                    }
                    
                    resp
                }
                Err(_) => {
                    (StatusCode::BAD_GATEWAY, "Failed to read response body").into_response()
                }
            }
        }
        Err(e) => {
            if e.is_timeout() {
                (StatusCode::GATEWAY_TIMEOUT, "Request timeout").into_response()
            } else if e.is_connect() {
                (StatusCode::BAD_GATEWAY, "Connection failed").into_response()
            } else {
                (StatusCode::BAD_GATEWAY, "Failed to fetch URL").into_response()
            }
        }
    }
}

#[tokio::main]
async fn main() {
    let app = Router::new().route("/proxy", get(proxy_handler));

    let listener = tokio::net::TcpListener::bind("127.0.0.1:3000")
        .await
        .unwrap();
    
    println!("Server running on http://127.0.0.1:3000");
    axum::serve(listener, app).await.unwrap();
}